(function(window,document){function container(){var id='toast-container';var el=document.getElementById(id);if(!el){el=document.createElement('div');el.id=id;document.body.appendChild(el)}el.className=toastr.options.positionClass||'toast-top-right';return el}function show(type,message){var opts=toastr.options||{};var item=document.createElement('div');var close=document.createElement('button');var text=document.createElement('span');var progress=document.createElement('div');var timeout=Number(opts.timeOut||3000);item.className='admin-toast admin-toast-'+type;text.textContent=message||'';close.type='button';close.className='admin-toast-close';close.innerHTML='&times;';close.onclick=function(){remove(item)};item.appendChild(text);if(opts.closeButton){item.appendChild(close)}if(opts.progressBar){progress.className='admin-toast-progress';progress.style.width='100%';progress.style.transition='width '+timeout+'ms linear';item.appendChild(progress);setTimeout(function(){progress.style.width='0'},20)}container().appendChild(item);setTimeout(function(){remove(item)},timeout)}function remove(item){if(item&&item.parentNode){item.parentNode.removeChild(item)}}var toastr=window.toastr||{};toastr.options=toastr.options||{};['success','error','warning','info'].forEach(function(type){toastr[type]=function(message){show(type,message)}});window.toastr=toastr})(window,document);
